import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../App.css';

const api = axios.create({
  baseURL: 'http://localhost:5000',
  // withCredentials: true,
});

function Login() {
  const [form, setForm] = useState({ login: '', password: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const response = await api.post('/login', {
        login: form.login,
        password: form.password
      });

      if (response.status === 200) {
        // Успешный вход - переходим на dashboard
        navigate('/');
      }
    } catch (err) {
      if (err.response) {
        setError(err.response.data.message || 'Ошибка входа');
      } else if (err.request) {
        setError('Нет ответа от сервера. Проверьте, запущен ли Flask.');
      } else {
        setError('Ошибка при отправке запроса');
      }
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setForm(prev => ({
      ...prev,
      [name]: value
    }));
    // Очищаем ошибку при вводе
    if (error) setError('');
  };

  return (
    <div className="login-page">
      <div className="login-container">
        <div className="login-card">
          <div className="login-header">
            <h1>Вход в систему</h1>
            <p>Введите ваши учетные данные</p>
          </div>

          {error && (
            <div className="error-message">
              <strong>Ошибка:</strong> {error}
            </div>
          )}

          <form onSubmit={handleSubmit} className="login-form">
            <div className="form-group">
              <label htmlFor="login">Логин:</label>
              <input
                type="text"
                id="login"
                name="login"
                value={form.login}
                onChange={handleInputChange}
                placeholder="Введите логин"
                required
                disabled={loading}
                autoComplete="username"
                autoFocus
              />
            </div>

            <div className="form-group">
              <label htmlFor="password">Пароль:</label>
              <input
                type="password"
                id="password"
                name="password"
                value={form.password}
                onChange={handleInputChange}
                placeholder="Введите пароль"
                required
                disabled={loading}
                autoComplete="current-password"
              />
            </div>

            <button
              type="submit"
              className="login-button"
              disabled={loading || !form.login || !form.password}
            >
              {loading ? 'Вход...' : 'Войти'}
            </button>
          </form>

          <div className="login-info">
            <p><strong>Для тестирования:</strong></p>
            <p>Логин: <code>admin</code></p>
            <p>Пароль: <code>admin123</code></p>
            <p><small>Или используйте свои данные из БД</small></p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;
